  Future<void> _shareSheetLink(SheetMeta sheet) async {
    if (_busy) {
      _toast('Ya hay una operaci\u00f3n en curso. Espera a que termine.');
      return;
    }
    if (!_featureService.isEnabled(BitFlowFeature.sharing)) {
      await _showUpgradeForFeature(BitFlowFeature.sharing);
      return;
    }

    final permission = await showCupertinoModalPopup<BitFlowSharePermission>(
      context: context,
      builder: (ctx) => CupertinoActionSheet(
        title: const Text('Compartir por link'),
        message: Text(_sheetDisplayTitle(sheet)),
        actions: [
          CupertinoActionSheetAction(
            onPressed: () => Navigator.of(ctx).pop(BitFlowSharePermission.view),
            child: const Text('Link solo lectura'),
          ),
          CupertinoActionSheetAction(
            onPressed: () => Navigator.of(ctx).pop(BitFlowSharePermission.edit),
            child: const Text('Link con edicion'),
          ),
        ],
        cancelButton: CupertinoActionSheetAction(
          onPressed: () => Navigator.of(ctx).pop(),
          child: const Text('Cancelar'),
        ),
      ),
    );
    if (permission == null) return;

    _beginBusyOperation(
      message: 'Preparando link para compartir...',
      canCancel: false,
    );
    try {
      final share = await _product.createShareLinkForSheet(
        meta: sheet,
        permission: permission,
        baseUrl: Uri.base.origin,
      );
      final shareUrl = share.url.trim();
      final parsedUrl = Uri.tryParse(shareUrl);
      if (shareUrl.isEmpty || parsedUrl == null || !parsedUrl.hasScheme) {
        _reportStartPageErrorMessage(
          'share_link_invalid',
          flow: AppErrorFlow.exportData,
          operation: 'share_sheet_link',
          fallbackMessage:
              'No pudimos generar un link v\u00e1lido para esta planilla.',
        );
        return;
      }
      final shareTitle = 'BitFlow | ${_sheetDisplayTitle(sheet)}';
      final shareText = '$shareTitle\n$shareUrl';
      var copiedToClipboard = false;
      try {
        await Clipboard.setData(ClipboardData(text: shareUrl));
        copiedToClipboard = true;
      } catch (_) {}
      try {
        await SharePlus.instance.share(
          ShareParams(
            subject: shareTitle,
            text: shareText,
          ),
        );
        if (!mounted) return;
        _toast(
          copiedToClipboard
              ? 'Compartir abierto. Link tambien copiado.'
              : 'Compartir abierto.',
        );
        return;
      } catch (shareError) {
        final outcome = classifyExportFlowOutcome(shareError);
        if (outcome == ExportFlowOutcome.cancelled) {
          if (!mounted) return;
          _toast(
            copiedToClipboard
                ? 'Link copiado al portapapeles.'
                : 'Compartir cancelado.',
          );
          return;
        }
      }
      if (!mounted) return;
      _toast(
        copiedToClipboard
            ? 'No pudimos abrir compartir. Link copiado al portapapeles.'
            : 'No pudimos abrir compartir. Intenta nuevamente.',
      );
    } catch (error) {
      if (error is StateError &&
          error.message ==
              _featureService.featureBlockedReason(BitFlowFeature.sharing)) {
        await _showUpgradeForFeature(BitFlowFeature.sharing);
        return;
      }
      _reportStartPageError(
        error,
        flow: AppErrorFlow.exportData,
        operation: 'share_sheet_link',
        fallbackMessage: 'No pudimos crear el link. Intenta nuevamente.',
      );
    } finally {
      _endBusyOperation();
    }
  }

  Future<void> _moveSheetToWorkspace(SheetMeta sheet) async {
    await _product.workspaces.reconcileSheets(_items.map((item) => item.id));
    if (!mounted) return;

    final currentWorkspaceId = _product.workspaces.workspaceForSheet(sheet.id);
    final nextWorkspaceId = await showCupertinoModalPopup<String>(
      context: context,
      builder: (ctx) => CupertinoActionSheet(
        title: const Text('Mover a workspace'),
        message: Text(_sheetDisplayTitle(sheet)),
        actions: [
          for (final workspace in _product.workspaces.workspaces.value)
            CupertinoActionSheetAction(
              onPressed: () => Navigator.of(ctx).pop(workspace.id),
              isDefaultAction: workspace.id == currentWorkspaceId,
              child: Text(
                workspace.id == currentWorkspaceId
                    ? '${workspace.name} (actual)'
                    : workspace.name,
              ),
            ),
        ],
        cancelButton: CupertinoActionSheetAction(
          onPressed: () => Navigator.of(ctx).pop(),
          child: const Text('Cancelar'),
        ),
      ),
    );
    if (nextWorkspaceId == null || nextWorkspaceId == currentWorkspaceId) {
      return;
    }

    await _product.workspaces.moveSheetToWorkspace(sheet.id, nextWorkspaceId);
    if (!mounted) return;

    final workspaceName = _product.workspaces.workspaces.value
        .where((workspace) => workspace.id == nextWorkspaceId)
        .map((workspace) => workspace.name)
        .cast<String?>()
        .firstWhere((name) => name != null, orElse: () => null);

    _toast(
      workspaceName == null
          ? 'Planilla movida.'
          : 'Planilla movida a $workspaceName.',
    );
    _reload();
  }

