  // --------------------- UI helpers ---------------------

  String _fmt(DateTime d) {
    final local = d.toLocal();
    final now = DateTime.now();
    final diff = now.difference(local);

    if (diff.inMinutes < 1) return 'justo ahora';
    if (diff.inMinutes < 60) return 'hace ${diff.inMinutes} min';
    if (diff.inHours < 24) return 'hace ${diff.inHours} h';

    final dd = local.day.toString().padLeft(2, '0');
    final mm = local.month.toString().padLeft(2, '0');
    final hh = local.hour.toString().padLeft(2, '0');
    final min = local.minute.toString().padLeft(2, '0');
    return '$dd/$mm $hh:$min';
  }

  bool _looksLikeEmail(String s) {
    final re = RegExp(r'^[^\s@]+@[^\s@]+\.[^\s@]+\.[^\s@]+$'); // fallback extra
    final re2 = RegExp(r'^[^\s@]+@[^\s@]+\.[^\s@]{2,}$');
    return (re2.hasMatch(s.trim()) || re.hasMatch(s.trim()));
  }

  List<SheetMeta> get _activeSheets {
    final list = _product.filterSheetsForCurrentWorkspace(
      _items.where((m) => !_trashDeletedAtMs.containsKey(m.id)),
    );
    list.sort((a, b) => b.updatedAt.compareTo(a.updatedAt));
    return list;
  }

  List<SheetMeta> get _recentSheets {
    final activeById = <String, SheetMeta>{
      for (final m in _activeSheets) m.id: m,
    };
    final entries = _sheetLastOpenedAtMs.entries
        .where((entry) => activeById.containsKey(entry.key))
        .toList(growable: false)
      ..sort((a, b) => b.value.compareTo(a.value));
    final recents = <SheetMeta>[
      for (final entry in entries) activeById[entry.key]!,
    ];
    if (recents.isNotEmpty) return recents;
    return _activeSheets;
  }

  List<SheetMeta> get _favoriteSheets {
    final active = _activeSheets
        .where((m) => _favoriteSheetIds.contains(m.id))
        .toList(growable: false);
    active.sort((a, b) {
      final openedA = _sheetLastOpenedAtMs[a.id] ?? 0;
      final openedB = _sheetLastOpenedAtMs[b.id] ?? 0;
      if (openedA != openedB) return openedB.compareTo(openedA);
      return b.updatedAt.compareTo(a.updatedAt);
    });
    return active;
  }

  List<SheetMeta> get _pinnedSheets {
    final active = _activeSheets
        .where((m) => _pinnedSheetIds.contains(m.id))
        .toList(growable: false);
    active.sort((a, b) {
      final openedA = _sheetLastOpenedAtMs[a.id] ?? 0;
      final openedB = _sheetLastOpenedAtMs[b.id] ?? 0;
      if (openedA != openedB) return openedB.compareTo(openedA);
      return b.updatedAt.compareTo(a.updatedAt);
    });
    return active;
  }

  bool _isFavoriteSheet(String sheetId) => _favoriteSheetIds.contains(sheetId);

  bool _isPinnedSheet(String sheetId) => _pinnedSheetIds.contains(sheetId);

  bool _isTextInputFocused() {
    final focus = FocusManager.instance.primaryFocus;
    if (focus == null) return false;
    return focus.context?.widget is EditableText;
  }

  KeyEventResult _onHomeKeyEvent(FocusNode node, KeyEvent event) {
    if (event is! KeyDownEvent) return KeyEventResult.ignored;
    if (_isTextInputFocused()) return KeyEventResult.ignored;
    final isMod = HardwareKeyboard.instance.isControlPressed ||
        HardwareKeyboard.instance.isMetaPressed;
    if (!isMod) return KeyEventResult.ignored;
    if (event.logicalKey == LogicalKeyboardKey.keyK) {
      unawaited(_openQuickSwitcher());
      return KeyEventResult.handled;
    }
    if (event.logicalKey == LogicalKeyboardKey.keyN) {
      unawaited(_createAndOpenSheet());
      return KeyEventResult.handled;
    }
    if (event.logicalKey == LogicalKeyboardKey.keyO) {
      unawaited(_openMostRecentSheet());
      return KeyEventResult.handled;
    }
    if (event.logicalKey == LogicalKeyboardKey.keyT) {
      unawaited(_newTemplateSheet());
      return KeyEventResult.handled;
    }
    return KeyEventResult.ignored;
  }

  Future<void> _openQuickSwitcher() async {
    if (!mounted) return;

    final actions = <CommandAction>[];

    for (final sheet in _activeSheets) {
      final title =
          sheet.title.trim().isEmpty ? 'Planilla sin titulo' : sheet.title;
      final suffix = _isFavoriteSheet(sheet.id) ? ' - Favorita' : '';
      actions.add(
        CommandAction(
          id: 'quick_sheet_${sheet.id}',
          label: title,
          subtitle: 'Planilla$suffix - ${_fmt(sheet.updatedAt)}',
          icon: _isFavoriteSheet(sheet.id)
              ? CupertinoIcons.star_fill
              : CupertinoIcons.doc_text,
          onSelected: () => unawaited(_open(sheet)),
        ),
      );
    }

    actions.addAll([
      CommandAction(
        id: 'quick_new_sheet',
        label: 'Nueva planilla',
        subtitle: 'Crear una planilla vac\u00eda',
        icon: CupertinoIcons.plus_rectangle_fill_on_rectangle_fill,
        onSelected: () => unawaited(_newSheet()),
      ),
      CommandAction(
        id: 'quick_from_template',
        label: 'Plantillas',
        subtitle: 'Abrir la galer\u00eda de plantillas',
        icon: CupertinoIcons.square_grid_2x2_fill,
        onSelected: () => unawaited(_newTemplateSheet()),
      ),
    ]);

    for (final template in _commercialTemplates) {
      actions.add(
        CommandAction(
          id: 'quick_template_${template.id}',
          label: template.name,
          subtitle: 'Pack de plantillas - ${template.pack}',
          icon: template.icon,
          onSelected: () => unawaited(_createAndOpenPackTemplate(template)),
        ),
      );
    }

    await showCommandPalette(
      context,
      title: 'Paleta de comandos',
      actions: actions,
    );
  }

  String _sheetDisplayTitle(SheetMeta sheet) {
    final title = sheet.title.trim();
    return title.isEmpty ? 'Planilla sin titulo' : title;
  }

  String _normalizedSheetTitle(String raw) {
    return raw.replaceAll(RegExp(r'\s+'), ' ').trim().toLowerCase();
  }

  bool _isActiveSheetTitleTaken(String raw, {String? excludeId}) {
    final wanted = _normalizedSheetTitle(raw);
    if (wanted.isEmpty) return false;
    for (final sheet in _items) {
      if (sheet.id == excludeId) continue;
      if (_trashDeletedAtMs.containsKey(sheet.id)) continue;
      if (_normalizedSheetTitle(sheet.title) == wanted) {
        return true;
      }
    }
    return false;
  }

  String? _validateActiveSheetTitle(String raw, {String? excludeId}) {
    final trimmed = raw.replaceAll(RegExp(r'\s+'), ' ').trim();
    if (trimmed.isEmpty) {
      return 'El nombre no puede quedar vacio.';
    }
    if (trimmed.length > 80) {
      return 'Usa un nombre de hasta 80 caracteres.';
    }
    if (_isActiveSheetTitleTaken(trimmed, excludeId: excludeId)) {
      return 'Ya existe una planilla activa con ese nombre.';
    }
    return null;
  }

  TemplateKind? _coreTemplateFromId(String raw) {
    switch (raw.trim()) {
      case 'plantilla':
        return TemplateKind.plantilla;
      case 'resistividades':
        return TemplateKind.resistividades;
      case 'inventario':
        return TemplateKind.inventario;
      case 'checklist':
        return TemplateKind.checklist;
      default:
        return null;
    }
  }

  _PackTemplateSpec? _packTemplateFromId(String raw) {
    final wanted = raw.trim();
    if (wanted.isEmpty) return null;
    for (final template in _commercialTemplates) {
      if (template.id == wanted) return template;
    }
    return null;
  }

  Future<void> _openMostRecentSheet() async {
    final recents = _recentSheets;
    if (recents.isEmpty) {
      _toast('No hay archivos recientes todav\u00eda.');
      await _openQuickSwitcher();
      return;
    }
    await _open(recents.first);
  }

  Future<void> _exportMostRecentSheet() async {
    final candidate = _recentSheets.isNotEmpty
        ? _recentSheets.first
        : (_activeSheets.isNotEmpty ? _activeSheets.first : null);
    if (candidate == null) {
      _toast('No hay planillas para exportar todav\u00eda.');
      return;
    }
    await _exportSheet(candidate);
  }

  _StartAutomationAction? _recentTemplateAutomation() {
    for (final sheet in _recentSheets.take(8)) {
      final raw = SheetStore.loadRaw(sheet.id);
      if (raw == null || raw.trim().isEmpty) continue;
      try {
        final decoded = jsonDecode(raw);
        if (decoded is! Map) continue;
        final model = decoded.cast<String, dynamic>();
        final templateId = (model['templateKind'] ?? '').toString().trim();
        if (templateId.isEmpty) continue;

        final packTemplate = _packTemplateFromId(templateId);
        if (packTemplate != null) {
          return _StartAutomationAction(
            id: 'automation_recent_template_${packTemplate.id}',
            icon: CupertinoIcons.square_grid_2x2,
            title: 'Repetir plantilla reciente',
            subtitle: 'Repetir ${packTemplate.name}',
            contextLabel: _sheetDisplayTitle(sheet),
            onSelected: () => _createAndOpenPackTemplate(packTemplate),
          );
        }

        final coreTemplate = _coreTemplateFromId(templateId);
        if (coreTemplate != null) {
          return _StartAutomationAction(
            id: 'automation_recent_template_${coreTemplate.name}',
            icon: CupertinoIcons.square_grid_2x2,
            title: 'Repetir plantilla reciente',
            subtitle: 'Repetir ${_sheetDisplayTitle(sheet)}',
            contextLabel: 'Basado en una planilla creada hace poco',
            onSelected: () => _createAndOpenSheet(template: coreTemplate),
          );
        }
      } catch (_) {}
    }
    return null;
  }

  List<_StartAutomationAction> _buildAutomationActions() {
    final actions = <_StartAutomationAction>[];
    final recents = _recentSheets;
    final recentTemplateAction = _recentTemplateAutomation();

    if (recents.isNotEmpty) {
      actions.add(
        _StartAutomationAction(
          id: 'automation_continue_latest',
          icon: CupertinoIcons.play_fill,
          title: 'Continuar \u00faltimo proyecto',
          subtitle: _sheetDisplayTitle(recents.first),
          contextLabel: '\u00daltima planilla abierta',
          onSelected: () => _open(recents.first),
        ),
      );
    } else {
      actions.add(
        _StartAutomationAction(
          id: 'automation_first_sheet',
          icon: CupertinoIcons.plus_rectangle_fill_on_rectangle_fill,
          title: 'Crear primera planilla',
          subtitle:
              'Empez\u00e1 con una hoja limpia y entr\u00e1 directo a editar',
          contextLabel: 'Mejor primer paso',
          onSelected: () => _createAndOpenSheet(),
        ),
      );
    }

    actions.add(
      _StartAutomationAction(
        id: 'automation_measurement',
        icon: CupertinoIcons.waveform_path_ecg,
        title: 'Crear planilla de medici\u00f3n',
        subtitle:
            'Abr\u00ed una plantilla t\u00e9cnica lista para cargar datos en campo',
        contextLabel: 'Ideal para trabajo t\u00e9cnico',
        onSelected: () => _createAndOpenSheet(
          template: TemplateKind.resistividades,
        ),
      ),
    );

    actions.add(
      _StartAutomationAction(
        id: 'automation_import',
        icon: CupertinoIcons.arrow_down_doc,
        title: 'Importar datos',
        subtitle:
            'Tra\u00e9 un ZIP de backup o paquete y segu\u00ed trabajando',
        contextLabel: 'Desde otro equipo o backup',
        onSelected: _importBackupZip,
      ),
    );

    actions.add(
      recentTemplateAction ??
          _StartAutomationAction(
            id: 'automation_template_gallery',
            icon: CupertinoIcons.square_grid_2x2,
            title: 'Abrir plantilla',
            subtitle:
                'Explor\u00e1 plantillas de medici\u00f3n, inventario y proyectos',
            contextLabel: 'Galer\u00eda de plantillas',
            onSelected: _newTemplateSheet,
          ),
    );

    return actions.take(4).toList(growable: false);
  }

