  Future<void> _signOutCurrentUser() async {
    if (!RuntimeFlags.isAuthRequired) {
      _toast('Modo demo activo: no hay sesion para cerrar.');
      return;
    }
    try {
      await AuthService.I.signOut();
    } catch (error) {
      _toast('No se pudo cerrar sesion: $error');
    }
  }

  Future<bool?> _confirmCupertino({
    BuildContext? ctx,
    required String title,
    required String message,
    required String okText,
    bool danger = false,
  }) async {
    final used = ctx ?? context;
    return showCupertinoDialog<bool>(
      context: used,
      builder: (dialogContext) => CupertinoAlertDialog(
        title: Text(title),
        content: Padding(
          padding: const EdgeInsets.only(top: 8),
          child: Text(message),
        ),
        actions: [
          CupertinoDialogAction(
            onPressed: () => Navigator.of(dialogContext).pop(false),
            child: const Text('Cancelar'),
          ),
          CupertinoDialogAction(
            onPressed: () => Navigator.of(dialogContext).pop(true),
            isDestructiveAction: danger,
            isDefaultAction: !danger,
            child: Text(okText),
          ),
