  // --------------------- Build ---------------------

  @override
  Widget build(BuildContext context) {
    final theme = Theme.of(context);
    final colors = _ApplePalette(
      isLight: theme.brightness == Brightness.light,
      colorScheme: theme.colorScheme,
      scaffold: theme.scaffoldBackgroundColor,
    );

    final pageBackground = theme.colorScheme.surface.withValues(alpha: 1);
    final cardBackground = colors.surface.withValues(alpha: 1);
    final borderColor = colors.separator.withValues(alpha: 1);

    final startupErrors = <String>[
      if ((_prefsLoadError ?? '').trim().isNotEmpty)
        'Preferencias: ${_prefsLoadError!.trim()}',
      if ((_orgLoadError ?? '').trim().isNotEmpty)
        'Organizacion: ${_orgLoadError!.trim()}',
    ];
    final showInitialLoading = !_prefsLoaded || !_orgLoaded;
    final recentSheets = _recentSheets.take(4).toList(growable: false);
    final favoriteSheets = _favoriteSheets.take(4).toList(growable: false);
    final pinnedSheets = _pinnedSheets.take(4).toList(growable: false);
    final automationActions = _buildAutomationActions();

    final mq = MediaQuery.of(context);
    final bottomPad = mq.padding.bottom;
    final isShortViewport = mq.size.height < 760;
    final showDebugBadge = kDebugMode || _kShowDebugBadge;
    final buildStamp = _buildStamp;
    final activeCount = _activeSheets.length;
    final recentCount = _recentSheets.length;
    final workspaceName = _currentWorkspace?.name ?? 'Personal';
    final planLabel = RuntimeFlags.monetizationEnabled
        ? (_entitlement.isPro ? 'Pro' : 'Free')
        : 'Libre';
    final headerTitle = activeCount == 0
        ? 'Listo para trabajar'
        : recentCount > 0
            ? 'Segu\u00ed donde lo dejaste'
            : 'Tu centro de trabajo diario';
    final headerDetail = activeCount == 0
        ? 'Cre\u00e1 una planilla, abr\u00ed una plantilla o import\u00e1 datos sin salir de este inicio.'
        : recentCount > 0
            ? 'Tus archivos recientes y acciones m\u00e1s \u00fatiles ya est\u00e1n listos para que avances en segundos.'
            : 'Abr\u00ed, busc\u00e1 o cre\u00e1 una nueva planilla desde un espacio claro para trabajo diario.';
    final headerMetrics = <Widget>[
      _StartMetricPill(
        label: 'Espacio',
        value: workspaceName,
        colors: colors,
      ),
      _StartMetricPill(
        label: 'Recientes',
        value: '$recentCount listos',
        colors: colors,
      ),
      _StartMetricPill(
        label: 'Modo',
        value: planLabel,
        colors: colors,
      ),
    ];
    final quickActions = <_StartQuickActionSpec>[
      _StartQuickActionSpec(
        key: const ValueKey('start-primary-new'),
        icon: CupertinoIcons.plus_rectangle_fill_on_rectangle_fill,
        title: 'Nueva planilla',
        subtitle: 'Cre\u00e1 una hoja limpia y entr\u00e1 directo a editar',
        shortcut: 'Ctrl/Cmd + N',
        onPressed: () => _createAndOpenSheet(),
      ),
      _StartQuickActionSpec(
        key: const ValueKey('start-primary-open-recent'),
        icon: CupertinoIcons.clock_fill,
        title: 'Abrir reciente',
        subtitle: recentSheets.isEmpty
            ? 'Reabrir\u00e1s tu \u00faltimo archivo apenas tengas uno'
            : _sheetDisplayTitle(recentSheets.first),
        shortcut: 'Ctrl/Cmd + O',
        onPressed: _openMostRecentSheet,
      ),
      _StartQuickActionSpec(
        key: const ValueKey('start-primary-search'),
        icon: CupertinoIcons.search,
        title: 'Buscar archivos',
        subtitle:
            'Paleta para archivos, acciones y navegaci\u00f3n r\u00e1pida',
        shortcut: 'Ctrl/Cmd + K',
        onPressed: _openQuickSwitcher,
      ),
      _StartQuickActionSpec(
        key: const ValueKey('start-primary-automate'),
        icon: CupertinoIcons.square_grid_2x2_fill,
        title: 'Plantillas',
        subtitle: 'Modelos listos para mediciones, inventario y proyectos',
        shortcut: 'Ctrl/Cmd + T',
        onPressed: _newTemplateSheet,
      ),
    ];
    final recentWorkPrimaryBucket = _StartBucketSpec(
      title: 'Recientes',
      subtitle: 'Retom\u00e1 trabajo activo sin buscar',
      emptyMessage: 'Abr\u00ed una planilla una vez y aparecer\u00e1 ac\u00e1.',
      items: recentSheets,
    );
    final recentWorkSecondaryBuckets = <_StartBucketSpec>[
      if (favoriteSheets.isNotEmpty)
        _StartBucketSpec(
          title: 'Favoritas',
          subtitle: 'Archivos a los que volv\u00e9s seguido',
          emptyMessage: 'Marca una planilla como favorita para tenerla cerca.',
          items: favoriteSheets,
        ),
      if (pinnedSheets.isNotEmpty)
        _StartBucketSpec(
          title: 'Fijadas',
          subtitle: 'Siempre visibles desde el inicio',
          emptyMessage: 'Fija una planilla para dejarla estable aca.',
          items: pinnedSheets,
        ),
    ];
    String noteForSheet(String sheetId) => (_sheetNotes[sheetId] ?? '').trim();

    final isBusy = _busy && _busyMessage.trim().isNotEmpty;
    return Focus(
      focusNode: _homeKeyFocus,
      autofocus: true,
      onKeyEvent: _onHomeKeyEvent,
      child: Scaffold(
        backgroundColor: theme.colorScheme.surface,
        body: ColoredBox(
          key: const ValueKey('start-base-fill'),
          color: pageBackground,
          child: SafeArea(
            bottom: false,
            child: Column(
              children: [
                if (isBusy)
                  Padding(
                    padding: const EdgeInsets.fromLTRB(16, 12, 16, 0),
                    child: LoadingState(
                      message: _busyMessage,
                      onCancel: (_busyCanCancel && !_busyCancelRequested)
                          ? _requestBusyCancel
                          : null,
                      cancelLabel: AppStrings.cancel,
                    ),
                  ),
                Expanded(
                  child: IgnorePointer(
                    ignoring: isBusy,
                    child: CustomScrollView(
                      controller: _homeScrollController,
                      keyboardDismissBehavior:
                          ScrollViewKeyboardDismissBehavior.onDrag,
                      cacheExtent: 4000,
                      slivers: [
                        CupertinoSliverRefreshControl(
                          onRefresh: () async => _reload(),
                        ),
                        SliverToBoxAdapter(
                          child: _StartHeaderSection(
                            colors: colors,
                            cardBackground: cardBackground,
                            borderColor: borderColor,
                            isShortViewport: isShortViewport,
                            headerTitle: headerTitle,
                            headerDetail: headerDetail,
                            headerMetrics: headerMetrics,
                            onToggleTheme: widget.onToggleTheme,
                            onOpenMore: () => _openMoreSheet(colors),
                          ),
                        ),
                        if (showInitialLoading)
                          const SliverToBoxAdapter(
                            child: Padding(
                              padding: EdgeInsets.fromLTRB(16, 0, 16, 10),
                              child: LoadingState(
                                message:
                                    'Preparando BitFlow para tu primer uso...',
                              ),
                            ),
                          ),
                        if (startupErrors.isNotEmpty)
                          SliverToBoxAdapter(
                            child: Padding(
                              padding: const EdgeInsets.fromLTRB(16, 0, 16, 10),
                              child: AppErrorState(
                                compact: true,
                                title: 'Algunas preferencias no se cargaron',
                                message:
                                    'BitFlow continuo con una configuracion segura para no bloquear el inicio.',
                                details: startupErrors.join('\n'),
                                actionLabel: 'Reintentar inicio',
                                onAction: () {
                                  setState(() {
                                    _prefsLoaded = false;
                                    _orgLoaded = false;
                                    _prefsLoadError = null;
                                    _orgLoadError = null;
                                  });
                                  unawaited(_loadPrefs());
                                  unawaited(_loadOrg());
                                },
                              ),
                            ),
                          ),
